query:
-- 1. Move BI00008 from C0295 (Marrickville) to C2862 (Sutherland)
UPDATE billing_items SET customerExternalId = 'C2862' WHERE externalId = 'BI00008';

-- 2. Move the 3 service assignments for BI00008 from C0295 to C2862
UPDATE service_billing_assignments 
SET customerExternalId = 'C2862'
WHERE billingItemExternalId = 'BI00008';

-- 3. Move the Vocus SIM services S6952, S6953 from C0295 to C2862 
-- (they were assigned to BI00008 which is Sutherland's billing item)
UPDATE services SET customerExternalId = 'C2862' WHERE externalId IN ('S6952', 'S6953');

-- 4. Move BI00086 from C2761 (Zambrero - Elizabeth shadow) to C0335 (Zambrero Elizabeth St)
UPDATE billing_items SET customerExternalId = 'C0335' WHERE externalId = 'BI00086';

-- 5. Move S0417 (ABB NBN) from C2761 to C0335
UPDATE services SET customerExternalId = 'C0335' WHERE externalId = 'S0417';

-- 6. Move the service assignment for BI00086/S0417 from C2761 to C0335
UPDATE service_billing_assignments 
SET customerExternalId = 'C0335'
WHERE billingItemExternalId = 'BI00086';

-- 7. Mark C2761 as merged/inactive (it was a shadow record)
UPDATE customers SET customerType = 'merged' WHERE externalId = 'C2761';

